artifacts.action_items:
[
  {
    "task": "Provide £15 million in innovation funding to support universities in accessing UKRI funding.",
    "owner": "HEFCW",
    "deadline": "none",
    "evidence": "The meeting discusses the financial sustainability of the higher education sector in Wales, focusing on the challenges faced by universities, the impact of demographic changes, and the implications of Brexit."
  },
  {
    "task": "Work with the sector to improve the accessibility of information on university income and expenditure.",
    "owner": "HEFCW",
    "deadline": "none",
    "evidence": "Bethan Owen: The reporting of the income and expenditure is largely provided, probably more so in narrative form in the accounts and the financial statements and annual reports of institutions."
  },
  {
    "task": "Deliver the recommendations of the Reid review, including increasing QR funding and supporting the transition away from EU funding.",
    "owner": "Welsh Government",
    "deadline": "none",
    "evidence": "The Welsh Government has committed in principle to delivering Reid."
  },
  {
    "task": "Monitor each university's financial situation and provide support where necessary.",
    "owner": "HEFCW",
    "deadline": "none",
    "evidence": "Bethan Owen: We monitor, we receive forecasts, five-year forecasts, and we meet frequently with all our universities now."
  },
  {
    "task": "Maintain the attractiveness of Welsh universities to students.",
    "owner": "HEFCW",
    "deadline": "none",
    "evidence": "Bethan Owen: Maintaining the attractiveness of Welsh universities to students, because a large proportion are coming not from just Wales, but from England and internationally—so, that's a key part—"
  },
  {
    "task": "Increase openness and transparency around the use of fee income.",
    "owner": "HEFCW",
    "deadline": "none",
    "evidence": "Bethan Owen: The reporting of the income and expenditure is largely provided, probably more so in narrative form in the accounts and the financial statements and annual reports of institutions."
  },
  {
    "task": "Provide £15 million in innovation funding to support universities in accessing UKRI funding.",
    "owner": "HEFCW",
    "deadline": "2020-21",
    "evidence": "Bethan Owen: One aspect that we do intend to fund—and this is from Diamond, as well as Reid—is to place funding back into the system for innovation."
  },
  {
    "task": "Develop a vision for research and innovation in Wales.",
    "owner": "HEFCW",
    "deadline": "none",
    "evidence": "Dr David Blaney: And, then, there's also the recommendation from Reid that Wales needs to be better embedded in the conversations that are going on on a UK-wide basis, so the Welsh Government has established a presence in London in respect of research, and we have a colleague in HEFCW who is fractionally embedded in the United Kingdom Research and Innovation specifically to respond to that recommendation."
  },
  {
    "task": "Provide £28 million of investment in student support-related activities from the fee and access plans.",
    "owner": "Universities",
    "deadline": "none",
    "evidence": "Dr David Blaney: The sector has committed over £28 million of investment in student support-related activities from the fee and access plans, and that includes, in many instances, bursaries that are designed to help students cope with the costs of accommodation and the cost of living more generally."
  }
]

